#include <stdio.h>
#include <stdlib.h>
#include <float.h>
#include <math.h>
#include <omp.h>

#include "kmeans.h"

/*----< euclid_dist_2() >----------------------------------------------------*/
/* multi-dimensional spatial Euclid distance square */
float euclid_dist_2(float *pt1,
                    float *pt2,
                    int    numdims)
{
    int i;
    float ans = 0.0;

    for (i = 0; i < numdims; i++)
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);

    return ans;
}

/*----< find_nearest_point() >-----------------------------------------------*/
int find_nearest_point(float  *pt,       /* [nfeatures] */
                       int     nfeatures,
                       float **pts,      /* [npts][nfeatures] */
                       int     npts)
{
    int index = 0;
    int i;
    float max_dist = FLT_MAX;

    for (i = 0; i < npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < max_dist) {
            max_dist = dist;
            index    = i;
        }
    }
    return index;
}

/*----< kmeans_clustering() >------------------------------------------------*/
float **kmeans_clustering(float **feature,    /* in: [npoints][nfeatures] */
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) /* out: [npoints] */
{
    int      i, j, k, n = 0;
    int     *new_centers_len;  /* [nclusters]: number of elements in each cluster */
    float    delta;
    float  **clusters;         /* out: [nclusters][nfeatures] */
    float  **new_centers;      /* [nclusters][nfeatures] */

    /* allocate space for returning variable clusters[] */
    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    /* randomly pick cluster centers */
    for (i = 0; i < nclusters; i++) {
        /* n is the index of the randomly picked data point */
        n = (int)(rand() % npoints);
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
    }

    /* initialize membership[] */
    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    /* allocate space for and initialize new_centers_len and new_centers */
    new_centers_len = (int*)   calloc(nclusters, sizeof(int));
    new_centers     = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0]  = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    /* iterate until convergence */
    do {
        delta = 0.0;

        #pragma omp parallel for \
                    shared(feature, clusters, membership, new_centers, new_centers_len) \
                    firstprivate(npoints, nclusters, nfeatures) \
                    private(i, j, k) \
                    schedule(static) \
                    reduction(+:delta)
        for (i = 0; i < npoints; i++) {
            int index;
            /* find the index of nearest cluster center */
            index = find_nearest_point(feature[i], nfeatures, clusters, nclusters);

            /* if membership changes, increase delta by 1 */
            if (membership[i] != index) {
                delta += 1.0;
                membership[i] = index;
            }

            /* update new cluster centers: sum of all objects in cluster */
            #pragma omp atomic
            new_centers_len[index]++;

            for (j = 0; j < nfeatures; j++) {
                #pragma omp atomic
                new_centers[index][j] += feature[i][j];
            }
        }

        /* replace old cluster centers with new_centers */
        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;   /* set back to 0 */
            }
            new_centers_len[i] = 0;   /* set back to 0 */
        }

    } while (delta > threshold);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}
